parameters.jsCode:
const allArticles = [];
let articleCounter = 1;

for (const item of $input.all()) {
  let raw = item.json.candidates?.[0]?.content?.parts?.[0]?.text || "";
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  if (!jsonMatch) {
    continue;
  }
  let jsonStr = jsonMatch[0];
  jsonStr = jsonStr.replace(/,(\s*[}\]])/g, "$1");
  jsonStr = jsonStr.replace(/[\u0000-\u0008\u000B\u000C\u000E-\u001F]/g, "");
  let parsed;
  try {
    parsed = JSON.parse(jsonStr);
  } catch (e) {
    continue;
  }
  if (parsed.articles && Array.isArray(parsed.articles)) {
    for (const article of parsed.articles) {
      allArticles.push({
        json: {
          article_number: articleCounter++,
          title_hindi: article.article_title || "",
          title_english: article.article_title_english || "",
          description_hindi: article.hindi_summary || "",
          description_english: article.english_summary || ""
        }
      });
    }
  }
}

return allArticles;

