parameters.jsCode:
let data;
try {
  data = $("Code in JavaScript4").item.json;
} catch (e) {
  data = $("Code in JavaScript4").first().json;
}
const results = data?.results || [];
return results.map(item => ({
  json: {
    title: item?.title || "Untitled",
    summary_hindi: item?.reframed_script_hindi || "",
    summary_english: item?.reframed_script_english || ""
  }
}));

const parts = $json.content?.parts || [];
const rawText = parts.map(p => p.text).join('\n').trim();
const jsonMatch = rawText.match(/\{[\s\S]*\}/);
let parsed = {};

if (jsonMatch) {
  let jsonStr = jsonMatch[0];
  jsonStr = jsonStr.replace(/,(\s*[}\]])/g, "$1");
  jsonStr = jsonStr.replace(/[\u0000-\u0008\u000B\u000C\u000E-\u001F]/g, "");
  try {
    parsed = JSON.parse(jsonStr);
  } catch (e) {
    parsed = {
      title: "JSON Parse Error",
      reframed_script_hindi: "Error parsing model JSON: " + e.message + "\nRaw Text: " + rawText,
      reframed_script_english: "",
      deviation_percent: 0,
      facts_added: [],
      facts_removed: []
    };
  }
} else {
  parsed = {
    title: "No JSON Found",
    reframed_script_hindi: "Model did not output JSON.\nRaw Text: " + rawText,
    reframed_script_english: "",
    deviation_percent: 0,
    facts_added: [],
    facts_removed: []
  };
}

parsed.title = parsed.title || "Untitled";
parsed.reframed_script_hindi = parsed.reframed_script_hindi || "";
parsed.reframed_script_english = parsed.reframed_script_english || "";
parsed.facts_added = Array.isArray(parsed.facts_added) ? parsed.facts_added : [];
parsed.facts_removed = Array.isArray(parsed.facts_removed) ? parsed.facts_removed : [];
parsed.deviation_percent = typeof parsed.deviation_percent === 'number' ? parsed.deviation_percent : 0;

return { json: { results: [parsed] } };

const binaryData = $input.first().binary;
const items = [];

for (let i = 1; i <= 4; i++) {
  const key = `File_${i}`;
  if (binaryData && binaryData[key]) {
    items.push({
      json: {
        image_number: i,
        binary_key: key
      },
      binary: {
        image: binaryData[key]
      }
    });
  }
}

return items;

