parameters.jsCode:
const binary = $input.item.binary;
const firstKey = Object.keys(binary || {})[0];
if (!firstKey) {
  throw new Error('ComfyUI1 returned no binary video data - check its output tab.');
}
const ts = Date.now();
return {
  json: {
    ...$input.item.json,
    inputPath: `/media/reel-processing/${ts}-input.mp4`,
    outputPath: `/media/reel-processing/${ts}-output.mp4`
  },
  binary: { video: binary[firstKey] }
};

const inputPath = $('Normalize Video Binary').item.json.inputPath;
const outputPath = $('Normalize Video Binary').item.json.outputPath;
const title = $('Code in JavaScript2').item.json.title || '';

const sanitize = (s) => (s || '')
  .replace(/[:'"\\%$`]/g, '')
  .replace(/\s+/g, ' ')
  .trim();

const FONT_PATH = '/usr/share/fonts/dejavu/DejaVuSans-Bold.ttf';
const escapePath = (s) => s.replace(/'/g, `'\\''`);

const headerText = 'Sri Ganganagar';
const tickerText = sanitize(title) + '     \u2022     ';
const tickerSpeed = 120;

const headerDrawtext = `drawtext=fontfile='${FONT_PATH}':text='${headerText}':fontsize=70:fontcolor=white:borderw=3:bordercolor=black:box=1:boxcolor=black@0.45:boxborderw=14:x=(w-text_w)/2:y=50`;

const tickerDrawtext = `drawtext=fontfile='${FONT_PATH}':text='${tickerText}':fontsize=38:fontcolor=white:borderw=2:bordercolor=black:box=1:boxcolor=black@0.45:boxborderw=10:x=w-mod(t*${tickerSpeed}\\,w+text_w):y=h-text_h-60`;

const command = `ffmpeg -y -i '${escapePath(inputPath)}' -vf "${headerDrawtext},${tickerDrawtext}" -c:a copy '${escapePath(outputPath)}'`;

return { json: { command, outputPath } };

